function main() {
  console.log('🏗️  建筑业教学任务生成开始\n');

  const months = {
    '01': { tasks: M01, label: '企业设立与首个项目中标' },
    '02': { tasks: M02, label: '基础施工推进与分包进场' },
    '03': { tasks: M03, label: '主体结构施工与材料采购' },
    '04': { tasks: M04, label: '主体施工推进与成本控制' },
    '05': { tasks: M05, label: '新项目启动与双项目并行' },
    '06': { tasks: M06, label: '半年进度冲刺与质保金处理' },
    '07': { tasks: M07, label: '设计变更与签证索赔' },
    '08': { tasks: M08, label: '高温雨季施工与成本管控' },
    '09': { tasks: M09, label: '首个项目竣工决算' },
    '10': { tasks: M10, label: '竣工审计与新项目承接' },
    '11': { tasks: M11, label: '年末盘点与进度款催收' },
    '12': { tasks: M12, label: '年终决算与利润分配' },
  };

  let written = 0;
  for (const [month, data] of Object.entries(months)) {
    if (data.tasks.length === 0) {
      console.log(`  ⏭️  ${month}月 跳过（待后续补充）`);
      continue;
    }
    console.log(`\n--- ${parseInt(month)}月 ${data.label} ---`);
    writeMonthFile(month, data.tasks);
    written++;
  }

  console.log(`\n✨ 生成完成！已写入 ${written} 个月份。`);
  if (written < 12) {
    console.log(`📌 待完成：${12 - written} 个月份（03-12月）需继续补充。`);
  }

  // 校验文件
  const files = fs.readdirSync(CONSTRUCTION_DIR).filter(f => /^\d{2}\.js$/.test(f));
  console.log(`\n📁 当前 ${CONSTRUCTION_DIR} 目录下的月份文件：`);
  for (const f of files.sort()) {
    const count = fs.readFileSync(path.join(CONSTRUCTION_DIR, f), 'utf8').split("title:").length - 1;
    console.log(`   ${f}: ${count} 个任务`);
  }
}

main();
